patch:
diff --git a/llvm/lib/Transforms/Scalar/GVN.cpp b/llvm/lib/Transforms/Scalar/GVN.cpp
index 7704e49c499d..9ae2035c4233 100644
--- a/llvm/lib/Transforms/Scalar/GVN.cpp
+++ b/llvm/lib/Transforms/Scalar/GVN.cpp
@@ -3170,6 +3170,7 @@ bool GVNPass::performPRE(Function &F) {
 /// the block inserted to the critical edge.
 BasicBlock *GVNPass::splitCriticalEdges(BasicBlock *Pred, BasicBlock *Succ) {
   // GVN does not require loop-simplify, do not try to preserve it if it is not
+  if (isa<IndirectBrInst>(Pred->getTerminator())) return nullptr;
   // possible.
   BasicBlock *BB = SplitCriticalEdge(
       Pred, Succ,
@@ -3191,6 +3192,7 @@ bool GVNPass::splitCriticalEdges() {
   bool Changed = false;
   do {
     std::pair<Instruction *, unsigned> Edge = ToSplit.pop_back_val();
+    if (isa<IndirectBrInst>(static_cast<Instruction *>(Edge.first))) continue;
     Changed |= SplitCriticalEdge(Edge.first, Edge.second,
                                  CriticalEdgeSplittingOptions(DT, LI, MSSAU)) !=
                nullptr;

